    random.seed(42)
    count = len(rows)
    target = 5100

    while count < target:
        is_hindi = random.random() < 0.45
        lang = "Hindi" if is_hindi else "English"
        titles = hindi_titles if is_hindi else english_titles
        directors = hindi_directors if is_hindi else english_directors
        actors_pool = hindi_actors if is_hindi else english_actors
        overviews = overviews_hi if is_hindi else overviews_en

        title_base = random.choice(titles)
        suffix = random.choice(["", " Part 2", " Returns", " Reloaded", " Reborn", " 2", " 3", " Final Chapter", " Origins", " Unleashed"])
        title = title_base + suffix

        if any(r["title"] == title for r in rows):
            continue

        genre = random.choice(genres_pool)
        director = random.choice(directors)
        cast_list = random.sample(actors_pool, min(4, len(actors_pool)))
        cast = ", ".join(cast_list)
        year = random.randint(1980, 2023)
        rating = round(random.uniform(4.5, 8.9), 1)
        overview = random.choice(overviews)

        rows.append({
            "title": title, "genres": genre, "language": lang,
            "director": director, "cast": cast, "year": year,
            "rating": rating, "overview": overview
        })
        count += 1

    return pd.DataFrame(rows)

